import{j as e,b as t,c as d,a2 as l}from"./chunks/framework.BDRKwY9B.js";const s=JSON.parse('{"title":"AUR CLI 路线图","description":"规划统一的应用工具链 aur，以及后续的打包与分发能力。","frontmatter":{"title":"AUR CLI 路线图","description":"规划统一的应用工具链 aur，以及后续的打包与分发能力。","order":4},"headers":[],"relativePath":"develop/aur-cli.md","filePath":"develop/aur-cli.md","lastUpdated":1778839555000}'),o={name:"develop/aur-cli.md"};function i(r,a,c,u,n,p){return t(),d("div",null,[...a[0]||(a[0]=[l('<h1 id="aur-cli-路线图" tabindex="-1">AUR CLI 路线图 <a class="header-anchor" href="#aur-cli-路线图" aria-label="Permalink to &quot;AUR CLI 路线图&quot;">​</a></h1><p><code>app.py</code> 目前是一个临时调试入口——功能可用但组织分散。后续计划将其升级为统一的 CLI 工具，命名为 <code>aur</code>，集中管理所有与 app 相关的操作。</p><p><strong>挼挼如是说</strong></p><blockquote><p><code>aur</code> 是给 app 开发者用的瑞士军刀——开发期用它调试、测试，分发期用它打包、安装。它不涉及 kernel 的职责，那是内核层的领域。</p></blockquote><h2 id="它要干什么" tabindex="-1">它要干什么 <a class="header-anchor" href="#它要干什么" aria-label="Permalink to &quot;它要干什么&quot;">​</a></h2><p><code>aur</code> 聚焦两类场景：</p><ul><li><strong>开发期</strong>：扫描应用、按配置加载、调命令、注入事件、手动走 tick</li><li><strong>分发期</strong>：打包 <code>.aur</code>、安装应用、卸载应用、初始化配置</li></ul><h2 id="命名约定" tabindex="-1">命名约定 <a class="header-anchor" href="#命名约定" aria-label="Permalink to &quot;命名约定&quot;">​</a></h2><p>一个名字用到底：</p><ul><li>CLI 叫 <code>aur</code></li><li>包后缀叫 <code>.aur</code></li><li>文档与帮助文案统一使用此命名</li></ul><h2 id="它和现状的关系" tabindex="-1">它和现状的关系 <a class="header-anchor" href="#它和现状的关系" aria-label="Permalink to &quot;它和现状的关系&quot;">​</a></h2><p>好消息是——基础设施已大部分就位，无需从头开始：</p><ul><li>目录扫描和 app 实例化已经能跑</li><li>app 级配置管理已经有了</li><li>独立测试入口 <code>app.py</code> 已经在干活了</li><li>每个 app 都有自己的 <code>README.md</code> 和 <code>config.example.json</code></li></ul><p>因此目标不是推倒重来，而是在现有基础上收敛、规范化。</p><h2 id="设计边界" tabindex="-1">设计边界 <a class="header-anchor" href="#设计边界" aria-label="Permalink to &quot;设计边界&quot;">​</a></h2><p><code>aur</code> 只负责应用层和控制面——不介入认知层。</p><h3 id="它该干的" tabindex="-1">它该干的 <a class="header-anchor" href="#它该干的" aria-label="Permalink to &quot;它该干的&quot;">​</a></h3><ul><li>列出所有可用 app</li><li>查看各 app 的启用状态</li><li>直接调用某个 app 的命令</li><li>注入测试事件</li><li>手动执行若干次 tick</li><li>打包、安装、卸载 app</li></ul><h3 id="它不该干的" tabindex="-1">它不该干的 <a class="header-anchor" href="#它不该干的" aria-label="Permalink to &quot;它不该干的&quot;">​</a></h3><ul><li>认知推理——那是 brain 层的职责</li><li>内核调度——那是 kernel 层的职责</li><li>系统级环境变量——保持职责边界</li></ul><h2 id="推荐的命令结构" tabindex="-1">推荐的命令结构 <a class="header-anchor" href="#推荐的命令结构" aria-label="Permalink to &quot;推荐的命令结构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>干什么</th></tr></thead><tbody><tr><td><code>aur list</code></td><td>列出可用 app 及其状态</td></tr><tr><td><code>aur run</code></td><td>按配置启动已启用的 app</td></tr><tr><td><code>aur command</code></td><td>直接调用某个 app 的命令</td></tr><tr><td><code>aur event</code></td><td>注入一个测试事件</td></tr><tr><td><code>aur tick</code></td><td>手动执行若干次 tick</td></tr><tr><td><code>aur config init</code></td><td>生成一份 <code>apps/config.yaml</code></td></tr><tr><td><code>aur pack</code></td><td>打包成 <code>.aur</code></td></tr><tr><td><code>aur install</code></td><td>安装一个 <code>.aur</code> 包</td></tr><tr><td><code>aur uninstall</code></td><td>卸载一个 app</td></tr></tbody></table><h2 id="aur-包格式建议" tabindex="-1"><code>.aur</code> 包格式建议 <a class="header-anchor" href="#aur-包格式建议" aria-label="Permalink to &quot;`.aur` 包格式建议&quot;">​</a></h2><p>第一版保持简单——zip 修改后缀即可。</p><p>一个最小可用的包至少需包含以下文件：</p><ul><li><code>manifest.yaml</code></li><li><code>__init__.py</code></li><li><code>runtime.py</code></li><li><code>README.md</code></li><li><code>config.example.json</code></li><li><code>aur.yaml</code></li></ul><h2 id="配置哲学" tabindex="-1">配置哲学 <a class="header-anchor" href="#配置哲学" aria-label="Permalink to &quot;配置哲学&quot;">​</a></h2><p>两层配置，各管各的：</p><table tabindex="0"><thead><tr><th>配置位置</th><th>管什么</th></tr></thead><tbody><tr><td><code>apps/config.yaml</code></td><td>平台视角：这个 app 开不开、怎么启</td></tr><tr><td><code>app-data/&lt;package&gt;/config.json</code></td><td>app 自己：我怎么理解我的配置</td></tr></tbody></table><p>这样设计的好处：</p><ul><li>平台只看&quot;开没开、怎么开&quot;</li><li>app 自己管 &quot;我的参数是什么意思&quot;</li></ul><h2 id="分阶段落地" tabindex="-1">分阶段落地 <a class="header-anchor" href="#分阶段落地" aria-label="Permalink to &quot;分阶段落地&quot;">​</a></h2><h3 id="第一阶段" tabindex="-1">第一阶段 <a class="header-anchor" href="#第一阶段" aria-label="Permalink to &quot;第一阶段&quot;">​</a></h3><ul><li>将 <code>app.py</code> 改造为子命令结构</li><li>帮助文案统一替换为 <code>aur</code></li></ul><h3 id="第二阶段" tabindex="-1">第二阶段 <a class="header-anchor" href="#第二阶段" aria-label="Permalink to &quot;第二阶段&quot;">​</a></h3><ul><li>确定 <code>aur.yaml</code> 的格式规范</li><li>确定 <code>.aur</code> 包的内容结构与校验规则</li></ul><h3 id="第三阶段" tabindex="-1">第三阶段 <a class="header-anchor" href="#第三阶段" aria-label="Permalink to &quot;第三阶段&quot;">​</a></h3><ul><li>实现 <code>pack / install / uninstall</code></li><li>添加配置自动补全</li></ul><h3 id="第四阶段" tabindex="-1">第四阶段 <a class="header-anchor" href="#第四阶段" aria-label="Permalink to &quot;第四阶段&quot;">​</a></h3><ul><li>添加 <code>--force</code>、<code>--purge-data</code> 选项</li><li>处理版本冲突</li><li>引入校验和 / 签名机制</li></ul><h2 id="当前结论" tabindex="-1">当前结论 <a class="header-anchor" href="#当前结论" aria-label="Permalink to &quot;当前结论&quot;">​</a></h2><p><code>aur</code> 的命名同时覆盖开发期与分发期，语义统一。方向已明确，只待逐步落地。</p>',42)])])}const b=e(o,[["render",i]]);export{s as __pageData,b as default};
